// MaterialCombiner.js
import React, { useState, useEffect,useCallback } from 'react';

const MaterialCombiner = ({ apiBaseUrl }) => {
    const [materials, setMaterials] = useState([]);
    const [selectedMaterials, setSelectedMaterials] = useState([]);
    const [totalCost, setTotalCost] = useState(0);

    const fetchAPI = useCallback(async (url, options = {}) => {
        const authToken = sessionStorage.getItem('authToken');
        const response = await fetch(url, {
          ...options,
          headers: {
            ...options.headers,
            'Authorization': `Bearer ${authToken}`,
          },
        });
        if (!response.ok) {
          const errorResponse = await response.json();
          throw new Error(errorResponse.message || `Error fetching ${url}`);
        }
        return response.json();
      }, []);

    useEffect(() => {
        // Fetch materials from the API
        fetchAPI(`${apiBaseUrl}/materiallistAPI`)
            .then(response => response.json())
            .then(data => setMaterials(data))
            .catch(error => console.error('Error fetching materials:', error));
    }, [apiBaseUrl, fetchAPI]);

    const handleMaterialSelect = (material) => {
        // Add or remove material from the selected list
        if (selectedMaterials.includes(material)) {
            setSelectedMaterials(selectedMaterials.filter(m => m !== material));
        } else {
            setSelectedMaterials([...selectedMaterials, material]);
        }
    };

    useEffect(() => {
        // Calculate total cost whenever selected materials change
        const total = selectedMaterials.reduce((sum, material) => sum + material.cost, 0);
        setTotalCost(total);
    }, [selectedMaterials]);

    return (
        <div>
            <h2>Combine Materials</h2>
            <ul>
                {materials.map(material => (
                    <li key={material.id}>
                        <input
                            type="checkbox"
                            checked={selectedMaterials.includes(material)}
                            onChange={() => handleMaterialSelect(material)}
                        />
                        {material.name} - ${material.cost}
                    </li>
                ))}
            </ul>
            <h3>Total Cost: ${totalCost}</h3>
        </div>
    );
};

export default MaterialCombiner;
